export interface Expense {
  id: string;
  amount: number;
  description: string;
  category: string;
  date: string; // ISO format
  rawTranscript?: string;
}

export type Category = 
  | 'Food' 
  | 'Transport' 
  | 'Shopping' 
  | 'Health' 
  | 'Utilities' 
  | 'Entertainment' 
  | 'Other';

export interface DailySummary {
  date: string;
  total: number;
  expenses: Expense[];
}

import { GoogleGenAI, Type } from "@google/genai";
import { Expense } from "../types";

const ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });

export const analyzeExpenseAudio = async (base64Audio: string, mimeType: string): Promise<Partial<Expense>[]> => {
  const model = 'gemini-3-flash-preview';

  const prompt = `
    Analyze the provided audio recording of a person speaking about their daily expenses.
    Extract each individual expense mentioned. For each expense, provide:
    - amount (as a number)
    - description (what was bought)
    - category (one of: Food, Transport, Shopping, Health, Utilities, Entertainment, Other)
    - date (the current date is ${new Date().toISOString().split('T')[0]}. If a specific past date is mentioned, use that, otherwise use today's date).

    Return a JSON array of objects.
  `;

  try {
    const response = await ai.models.generateContent({
      model: model,
      contents: {
        parts: [
          {
            inlineData: {
              mimeType: mimeType,
              data: base64Audio,
            },
          },
          { text: prompt },
        ],
      },
      config: {
        responseMimeType: "application/json",
        responseSchema: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              amount: { type: Type.NUMBER, description: "The cost of the item" },
              description: { type: Type.STRING, description: "A short description of the expense" },
              category: { type: Type.STRING, description: "The category of spending" },
              date: { type: Type.STRING, description: "ISO 8601 date string YYYY-MM-DD" },
            },
            required: ["amount", "description", "category", "date"],
          },
        },
      },
    });

    const text = response.text;
    if (!text) return [];

    return JSON.parse(text);
  } catch (error) {
    console.error("Error analyzing audio with Gemini:", error);
    throw error;
  }
};

import React, { useState, useRef, useEffect } from 'react';
import { Mic, Square, Loader2, Sparkles } from 'lucide-react';

interface VoiceRecorderProps {
  onRecordingComplete: (base64: string, mimeType: string) => void;
  isProcessing: boolean;
}

const VoiceRecorder: React.FC<VoiceRecorderProps> = ({ onRecordingComplete, isProcessing }) => {
  const [isRecording, setIsRecording] = useState(false);
  const [recordingTime, setRecordingTime] = useState(0);
  const mediaRecorderRef = useRef<MediaRecorder | null>(null);
  const chunksRef = useRef<Blob[]>([]);
  const timerRef = useRef<number | null>(null);

  useEffect(() => {
    if (isRecording) {
      timerRef.current = window.setInterval(() => {
        setRecordingTime(prev => prev + 1);
      }, 1000);
    } else {
      if (timerRef.current) clearInterval(timerRef.current);
      setRecordingTime(0);
    }
    return () => {
      if (timerRef.current) clearInterval(timerRef.current);
    };
  }, [isRecording]);

  const startRecording = async () => {
    try {
      const stream = await navigator.mediaDevices.getUserMedia({ audio: true });
      const mediaRecorder = new MediaRecorder(stream);
      mediaRecorderRef.current = mediaRecorder;
      chunksRef.current = [];

      mediaRecorder.ondataavailable = (e) => {
        if (e.data.size > 0) chunksRef.current.push(e.data);
      };

      mediaRecorder.onstop = async () => {
        const audioBlob = new Blob(chunksRef.current, { type: 'audio/webm' });
        const reader = new FileReader();
        reader.readAsDataURL(audioBlob);
        reader.onloadend = () => {
          const base64data = reader.result as string;
          const base64Content = base64data.split(',')[1];
          onRecordingComplete(base64Content, 'audio/webm');
        };
        stream.getTracks().forEach(track => track.stop());
      };

      mediaRecorder.start();
      setIsRecording(true);
    } catch (err) {
      console.error("Failed to start recording:", err);
      alert("Please ensure microphone permissions are granted.");
    }
  };

  const stopRecording = () => {
    if (mediaRecorderRef.current && isRecording) {
      mediaRecorderRef.current.stop();
      setIsRecording(false);
    }
  };

  const formatTime = (seconds: number) => {
    const mins = Math.floor(seconds / 60);
    const secs = seconds % 60;
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  return (
    <div className="flex flex-col items-center justify-center p-8 bg-white rounded-3xl shadow-xl border border-slate-100 transition-all duration-300">
      <div className="relative mb-6">
        {isRecording && (
          <div className="absolute inset-0 bg-red-400 rounded-full animate-ping opacity-25"></div>
        )}
        <button
          onClick={isRecording ? stopRecording : startRecording}
          disabled={isProcessing}
          className={`relative z-10 p-8 rounded-full shadow-lg transition-all duration-300 ${
            isRecording 
              ? 'bg-red-500 hover:bg-red-600' 
              : 'bg-indigo-600 hover:bg-indigo-700'
          } ${isProcessing ? 'opacity-50 cursor-not-allowed' : ''}`}
        >
          {isProcessing ? (
            <Loader2 className="w-10 h-10 text-white animate-spin" />
          ) : isRecording ? (
            <Square className="w-10 h-10 text-white fill-current" />
          ) : (
            <Mic className="w-10 h-10 text-white" />
          )}
        </button>
      </div>

      <div className="text-center">
        <h3 className="text-xl font-semibold text-slate-800 mb-1">
          {isProcessing ? "Analyzing expenses..." : isRecording ? "Recording..." : "Speak your expenses"}
        </h3>
        <p className="text-slate-500 text-sm">
          {isProcessing 
            ? "Gemini AI is processing your voice" 
            : isRecording 
              ? `Elapsed time: ${formatTime(recordingTime)}` 
              : "Try: 'I spent 15 dollars on lunch and 5 on coffee'"}
        </p>
      </div>

      {!isRecording && !isProcessing && (
        <div className="mt-6 flex items-center gap-2 px-4 py-2 bg-indigo-50 text-indigo-700 rounded-full text-xs font-medium animate-bounce">
          <Sparkles className="w-3 h-3" />
          AI powered voice logging
        </div>
      )}
    </div>
  );
};

export default VoiceRecorder;

import React from 'react';
import { Expense } from '../types';
import { ChevronLeft, ChevronRight } from 'lucide-react';

interface ExpenseCalendarProps {
  expenses: Expense[];
  selectedDate: string;
  onDateSelect: (date: string) => void;
}

const ExpenseCalendar: React.FC<ExpenseCalendarProps> = ({ expenses, selectedDate, onDateSelect }) => {
  const [currentMonth, setCurrentMonth] = React.useState(new Date());

  const daysInMonth = (year: number, month: number) => new Date(year, month + 1, 0).getDate();
  const firstDayOfMonth = (year: number, month: number) => new Date(year, month, 1).getDay();

  const prevMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() - 1));
  const nextMonth = () => setCurrentMonth(new Date(currentMonth.getFullYear(), currentMonth.getMonth() + 1));

  const year = currentMonth.getFullYear();
  const month = currentMonth.getMonth();
  const totalDays = daysInMonth(year, month);
  const offset = firstDayOfMonth(year, month);

  const monthName = currentMonth.toLocaleString('default', { month: 'long' });

  const getDailyTotal = (day: number) => {
    const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
    return expenses
      .filter(e => e.date === dateStr)
      .reduce((sum, e) => sum + e.amount, 0);
  };

  const isToday = (day: number) => {
    const today = new Date();
    return today.getDate() === day && today.getMonth() === month && today.getFullYear() === year;
  };

  const isSelected = (day: number) => {
    const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;
    return selectedDate === dateStr;
  };

  return (
    <div className="bg-white rounded-3xl shadow-sm border border-slate-100 p-6">
      <div className="flex items-center justify-between mb-6">
        <h3 className="text-lg font-bold text-slate-800">{monthName} {year}</h3>
        <div className="flex gap-2">
          <button onClick={prevMonth} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
            <ChevronLeft className="w-5 h-5 text-slate-600" />
          </button>
          <button onClick={nextMonth} className="p-2 hover:bg-slate-100 rounded-lg transition-colors">
            <ChevronRight className="w-5 h-5 text-slate-600" />
          </button>
        </div>
      </div>

      <div className="grid grid-cols-7 gap-2">
        {['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'].map(day => (
          <div key={day} className="text-center text-xs font-semibold text-slate-400 py-2 uppercase tracking-wider">
            {day}
          </div>
        ))}

        {Array.from({ length: offset }).map((_, i) => (
          <div key={`empty-${i}`} className="h-16"></div>
        ))}

        {Array.from({ length: totalDays }).map((_, i) => {
          const day = i + 1;
          const total = getDailyTotal(day);
          const dateStr = `${year}-${(month + 1).toString().padStart(2, '0')}-${day.toString().padStart(2, '0')}`;

          return (
            <button
              key={day}
              onClick={() => onDateSelect(dateStr)}
              className={`h-16 rounded-xl flex flex-col items-center justify-center transition-all border ${
                isSelected(day)
                  ? 'bg-indigo-600 border-indigo-600 text-white shadow-md'
                  : isToday(day)
                  ? 'bg-indigo-50 border-indigo-100 text-indigo-700'
                  : 'bg-slate-50 border-transparent hover:border-slate-200 text-slate-700'
              }`}
            >
              <span className="text-sm font-medium">{day}</span>
              {total > 0 && (
                <span className={`text-[10px] mt-1 font-bold ${isSelected(day) ? 'text-indigo-100' : 'text-slate-500'}`}>
                  ${total.toFixed(0)}
                </span>
              )}
            </button>
          );
        })}
      </div>
    </div>
  );
};

export default ExpenseCalendar;

import React, { useMemo } from 'react';
import { Expense } from '../types';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell, PieChart, Pie } from 'recharts';
import { ArrowUpRight, ArrowDownRight, Wallet, ShoppingBag, CreditCard, Filter } from 'lucide-react';

interface DashboardProps {
  expenses: Expense[];
  selectedDate: string;
}

const Dashboard: React.FC<DashboardProps> = ({ expenses, selectedDate }) => {
  const filteredExpenses = useMemo(() => {
    return expenses.filter(e => e.date === selectedDate);
  }, [expenses, selectedDate]);

  const totalSpentAllTime = expenses.reduce((sum, e) => sum + e.amount, 0);
  const totalSpentSelectedDay = filteredExpenses.reduce((sum, e) => sum + e.amount, 0);

  const categoryData = useMemo(() => {
    const cats: Record<string, number> = {};
    expenses.forEach(e => {
      cats[e.category] = (cats[e.category] || 0) + e.amount;
    });
    return Object.entries(cats).map(([name, value]) => ({ name, value }));
  }, [expenses]);

  const COLORS = ['#6366f1', '#10b981', '#f59e0b', '#ef4444', '#8b5cf6', '#ec4899', '#64748b'];

  return (
    <div className="space-y-6">
      {/* Top Cards */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-indigo-50 rounded-2xl">
            <Wallet className="w-6 h-6 text-indigo-600" />
          </div>
          <div>
            <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Total Lifetime</p>
            <h4 className="text-2xl font-bold text-slate-800">${totalSpentAllTime.toLocaleString()}</h4>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-emerald-50 rounded-2xl">
            <CreditCard className="w-6 h-6 text-emerald-600" />
          </div>
          <div>
            <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Spent on {selectedDate}</p>
            <h4 className="text-2xl font-bold text-slate-800">${totalSpentSelectedDay.toLocaleString()}</h4>
          </div>
        </div>

        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100 flex items-center gap-4">
          <div className="p-3 bg-amber-50 rounded-2xl">
            <ShoppingBag className="w-6 h-6 text-amber-600" />
          </div>
          <div>
            <p className="text-slate-500 text-xs font-medium uppercase tracking-wider">Average Daily</p>
            <h4 className="text-2xl font-bold text-slate-800">
              ${(totalSpentAllTime / (new Set(expenses.map(e => e.date)).size || 1)).toFixed(0)}
            </h4>
          </div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        {/* Category Breakdown */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <h3 className="text-lg font-bold text-slate-800 mb-6 flex items-center gap-2">
            <Filter className="w-5 h-5 text-indigo-600" />
            Spending by Category
          </h3>
          <div className="h-64">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={80}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                  ))}
                </Pie>
                <Tooltip 
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 12px rgba(0,0,0,0.1)' }}
                  formatter={(value: number) => [`$${value}`, 'Amount']}
                />
              </PieChart>
            </ResponsiveContainer>
          </div>
          <div className="mt-4 grid grid-cols-2 gap-2">
            {categoryData.map((cat, i) => (
              <div key={cat.name} className="flex items-center gap-2">
                <div className="w-3 h-3 rounded-full" style={{ backgroundColor: COLORS[i % COLORS.length] }}></div>
                <span className="text-xs text-slate-600 font-medium">{cat.name}: ${cat.value}</span>
              </div>
            ))}
          </div>
        </div>

        {/* Selected Date List */}
        <div className="bg-white p-6 rounded-3xl shadow-sm border border-slate-100">
          <div className="flex items-center justify-between mb-6">
            <h3 className="text-lg font-bold text-slate-800">History: {selectedDate}</h3>
            <span className="text-xs font-semibold px-2 py-1 bg-slate-100 text-slate-600 rounded-lg">
              {filteredExpenses.length} Items
            </span>
          </div>

          <div className="space-y-4 max-h-[350px] overflow-y-auto pr-2 custom-scrollbar">
            {filteredExpenses.length > 0 ? (
              filteredExpenses.map((expense) => (
                <div key={expense.id} className="group flex items-center justify-between p-4 bg-slate-50 hover:bg-indigo-50 rounded-2xl transition-all border border-transparent hover:border-indigo-100">
                  <div className="flex items-center gap-4">
                    <div className={`w-10 h-10 rounded-full flex items-center justify-center text-white font-bold text-sm bg-indigo-500`}>
                      {expense.category[0]}
