                      <p className="text-slate-500 text-xs">{expense.category}</p>
                    </div>
                  </div>
                  <div className="text-right">
                    <p className="text-slate-800 font-bold">${expense.amount.toFixed(2)}</p>
                  </div>
                </div>
              ))
            ) : (
              <div className="flex flex-col items-center justify-center h-48 text-slate-400">
                <CreditCard className="w-12 h-12 mb-2 opacity-20" />
                <p className="text-sm">No expenses logged for this day</p>
              </div>
            )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { Expense } from './types';
import VoiceRecorder from './components/VoiceRecorder';
import ExpenseCalendar from './components/ExpenseCalendar';
import Dashboard from './components/Dashboard';
import { analyzeExpenseAudio } from './services/geminiService';
import { LayoutDashboard, Calendar, Mic2, Settings, History, Wallet } from 'lucide-react';

const App: React.FC = () => {
  const [expenses, setExpenses] = useState<Expense[]>([]);
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);
  const [isProcessing, setIsProcessing] = useState(false);
  const [activeTab, setActiveTab] = useState<'dashboard' | 'calendar' | 'record'>('dashboard');

  // Load from local storage
  useEffect(() => {
    const saved = localStorage.getItem('spendvoice_expenses');
    if (saved) {
      try {
        setExpenses(JSON.parse(saved));
      } catch (e) {
        console.error("Failed to load expenses", e);
      }
    }
  }, []);

  // Save to local storage
  useEffect(() => {
    localStorage.setItem('spendvoice_expenses', JSON.stringify(expenses));
  }, [expenses]);

  const handleRecordingComplete = async (base64: string, mimeType: string) => {
    setIsProcessing(true);
    try {
      const results = await analyzeExpenseAudio(base64, mimeType);

      const newExpenses: Expense[] = results.map(res => ({
        id: Math.random().toString(36).substring(7),
        amount: res.amount || 0,
        description: res.description || "Uncategorized Item",
        category: res.category || "Other",
        date: res.date || new Date().toISOString().split('T')[0],
      }));

      setExpenses(prev => [...prev, ...newExpenses]);
      // Switch back to dashboard to show results
      setActiveTab('dashboard');
      if (newExpenses.length > 0) {
        setSelectedDate(newExpenses[0].date);
      }
    } catch (err) {
      console.error(err);
      alert("Error processing audio. Please try again.");
    } finally {
      setIsProcessing(false);
    }
  };

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col pb-24 md:pb-0 md:pl-20">
      {/* Sidebar (Desktop) / Bottom Bar (Mobile) */}
      <nav className="fixed bottom-0 left-0 w-full bg-white border-t border-slate-200 p-4 flex justify-around items-center z-50 md:top-0 md:left-0 md:w-20 md:h-full md:flex-col md:border-t-0 md:border-r md:py-8">
        <div className="hidden md:flex mb-8">
          <div className="w-10 h-10 bg-indigo-600 rounded-2xl flex items-center justify-center shadow-lg shadow-indigo-200">
            <Wallet className="w-6 h-6 text-white" />
          </div>
        </div>

        <button 
          onClick={() => setActiveTab('dashboard')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'dashboard' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <LayoutDashboard className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase md:hidden">Home</span>
        </button>

        <button 
          onClick={() => setActiveTab('calendar')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'calendar' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <Calendar className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase md:hidden">Calendar</span>
        </button>

        <button 
          onClick={() => setActiveTab('record')}
          className={`flex flex-col items-center gap-1 transition-colors ${activeTab === 'record' ? 'text-indigo-600' : 'text-slate-400 hover:text-slate-600'}`}
        >
          <Mic2 className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase md:hidden">Log</span>
        </button>

        <div className="mt-auto hidden md:block">
          <Settings className="w-6 h-6 text-slate-400 hover:text-slate-600 cursor-pointer" />
        </div>
      </nav>

      {/* Header */}
      <header className="bg-white border-b border-slate-100 p-6 md:p-8 flex items-center justify-between sticky top-0 z-40">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">SpendVoice</h1>
          <p className="text-slate-500 text-sm font-medium">Your financial story, told by you.</p>
        </div>
        <div className="flex items-center gap-3">
          <div className="hidden md:block text-right mr-2">
            <p className="text-xs font-bold text-slate-400 uppercase">Welcome back</p>
            <p className="text-sm font-bold text-slate-800">Money Master</p>
          </div>
          <img 
            src="https://picsum.photos/100/100" 
            alt="User avatar" 
            className="w-10 h-10 rounded-full border-2 border-indigo-100 shadow-sm"
          />
        </div>
      </header>

      {/* Main Content Area */}
      <main className="p-4 md:p-8 max-w-6xl mx-auto w-full animate-in fade-in slide-in-from-bottom-4 duration-500">

        {activeTab === 'record' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8">
            <VoiceRecorder 
              onRecordingComplete={handleRecordingComplete} 
              isProcessing={isProcessing} 
            />
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard expenses={expenses} selectedDate={selectedDate} />
        )}

        {activeTab === 'calendar' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className="lg:col-span-8">
              <ExpenseCalendar 
                expenses={expenses} 
                selectedDate={selectedDate} 
                onDateSelect={setSelectedDate} 
              />
            </div>
            <div className="lg:col-span-4 bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-fit">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <History className="w-5 h-5 text-indigo-600" />
                  Details
                </h3>
                <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
                  {selectedDate}
                </span>
              </div>
              <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2">
                {expenses.filter(e => e.date === selectedDate).length > 0 ? (
                  expenses.filter(e => e.date === selectedDate).map(e => (
                    <div key={e.id} className="p-3 bg-slate-50 rounded-xl flex justify-between items-center border border-slate-100">
                      <div>
                        <p className="text-sm font-bold text-slate-800">{e.description}</p>
                        <p className="text-[10px] text-slate-500 font-medium uppercase">{e.category}</p>
                      </div>
                      <p className="font-bold text-indigo-600">${e.amount.toFixed(2)}</p>
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-slate-400 text-center py-8">No records for this date.</p>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Floating Action Button for recording (Quick Access) */}
