          <span className="text-[10px] font-bold uppercase md:hidden">Log</span>
        </button>

        <div className="mt-auto flex flex-col items-center gap-6 hidden md:flex">
          <button 
            onClick={handleResetAll}
            title="Reset All Data"
            className="p-2 text-slate-400 hover:text-red-600 transition-colors"
          >
            <Trash2 className="w-6 h-6" />
          </button>
          <Settings className="w-6 h-6 text-slate-400 hover:text-slate-600 cursor-pointer" />
        </div>

        {/* Mobile Reset Button */}
        <button 
          onClick={handleResetAll}
          className="flex flex-col items-center gap-1 text-slate-400 hover:text-red-600 md:hidden"
        >
          <Trash2 className="w-6 h-6" />
          <span className="text-[10px] font-bold uppercase">Reset</span>
        </button>
      </nav>

      {/* Header */}
      <header className="bg-white border-b border-slate-100 p-6 md:p-8 flex items-center justify-between sticky top-0 z-40">
        <div>
          <h1 className="text-2xl font-black text-slate-800 tracking-tight">SpendVoice</h1>
          <p className="text-slate-500 text-sm font-medium">Your financial story, told by you.</p>
        </div>
        <div className="flex items-center gap-3">
          <div className="hidden md:block text-right mr-2">
            <p className="text-xs font-bold text-slate-400 uppercase">Welcome back</p>
            <p className="text-sm font-bold text-slate-800">Money Master</p>
          </div>
          <img 
            src="https://picsum.photos/100/100" 
            alt="User avatar" 
            className="w-10 h-10 rounded-full border-2 border-indigo-100 shadow-sm"
          />
        </div>
      </header>

      {/* Main Content Area */}
      <main className="p-4 md:p-8 max-w-6xl mx-auto w-full animate-in fade-in slide-in-from-bottom-4 duration-500">

        {activeTab === 'record' && (
          <div className="flex flex-col items-center justify-center min-h-[60vh] space-y-8">
            <VoiceRecorder 
              onRecordingComplete={handleRecordingComplete} 
              isProcessing={isProcessing} 
            />
          </div>
        )}

        {activeTab === 'dashboard' && (
          <Dashboard 
            expenses={expenses} 
            selectedDate={selectedDate} 
            onDelete={handleDeleteExpense}
            onUpdate={handleUpdateExpense}
          />
        )}

        {activeTab === 'calendar' && (
          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            <div className="lg:col-span-8">
              <ExpenseCalendar 
                expenses={expenses} 
                selectedDate={selectedDate} 
                onDateSelect={setSelectedDate} 
              />
            </div>
            <div className="lg:col-span-4 bg-white rounded-3xl p-6 shadow-sm border border-slate-100 h-fit">
              <div className="flex items-center justify-between mb-4">
                <h3 className="text-lg font-bold text-slate-800 flex items-center gap-2">
                  <History className="w-5 h-5 text-indigo-600" />
                  Details
                </h3>
                <span className="text-xs font-bold text-indigo-600 bg-indigo-50 px-2 py-1 rounded">
                  {selectedDate}
                </span>
              </div>
              <div className="space-y-4 max-h-[500px] overflow-y-auto pr-2">
                {expenses.filter(e => e.date === selectedDate).length > 0 ? (
                  expenses.filter(e => e.date === selectedDate).map(e => (
                    <div key={e.id} className="p-3 bg-slate-50 rounded-xl flex justify-between items-center border border-slate-100">
                      <div>
                        <p className="text-sm font-bold text-slate-800">{e.description}</p>
                        <p className="text-[10px] text-slate-500 font-medium uppercase">{e.category}</p>
                      </div>
                      <p className="font-bold text-indigo-600">${e.amount.toFixed(2)}</p>
                    </div>
                  ))
                ) : (
                  <p className="text-sm text-slate-400 text-center py-8">No records for this date.</p>
                )}
              </div>
            </div>
          </div>
        )}
      </main>

      {/* Floating Action Button for recording (Quick Access) */}
      {activeTab !== 'record' && (
        <button 
          onClick={() => setActiveTab('record')}
          className="fixed bottom-24 right-6 md:bottom-8 md:right-8 p-5 bg-indigo-600 text-white rounded-full shadow-2xl hover:bg-indigo-700 transition-all hover:scale-110 active:scale-95 z-50 group"
        >
          <Mic2 className="w-6 h-6" />
          <span className="absolute right-16 top-1/2 -translate-y-1/2 bg-slate-800 text-white text-xs py-2 px-3 rounded-lg opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none whitespace-nowrap font-medium">
            Quick Voice Log
          </span>
        </button>
      )}
    </div>
  );
};

export default App;
